    30→	async create({
    31→		data,
    32→	}: {
    33→		data: IStyleAlternativeCreate;
    34→	}): Promise<IStyleAlternativeBase> {
    35→		const _id = randomUUID();
    36→
    37→		const insertData: IStyleAlternativeCreate & { _id: IStyleAlternativeBase['_id'] } = {
    38→			...data,
    39→			_id,
    40→		};
    41→
    42→		const dto = plainToInstance(CreateStyleAlternativeDto, insertData);
    43→		const errors = await validate(dto);
    44→
    45→		if (errors.length > 0) {
    46→			this.logger.error(
    47→				`Validation failed for style alternative data: ${this.formatValidationErrors({ errors })}`,
    48→			);
    49→			throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
    50→		}
    51→
    52→		try {
    53→			const res = await this.knexWrite.transaction(async (trx) => {
    54→				await trx(this.tableName).insert(insertData);
    55→
    56→				return await trx<BaseStyleAlternativeDto>(this.tableName)
    57→					.where({
    58→						style_id: data.style_id,
    59→						alternative_style_id: data.alternative_style_id,
    60→					})
    61→					.whereNull('deleted_at')
    62→					.orderBy('created_at', 'desc')
    63→					.first();
    64→			});
    65→
    66→			if (!res) {
    67→				this.logger.error(`Failed to insert style alternative with ID ${_id}`);
    68→				throw new Error(`Failed to insert style alternative with ID ${_id}`);
    69→			}
    70→
    71→			this.logger.debug(`Inserted style alternative with ID ${_id}`);
    72→
    73→			return instanceToPlain<BaseStyleAlternativeDto>(res) as IStyleAlternativeBase;
    74→		} catch (error: unknown) {
    75→			const err = error instanceof Error ? error : new Error(String(error));
    76→			this.logger.error(`Failed to create style alternative: ${err.message}`);
    77→			throw err;
    78→		}
    79→	}
