    89→				.whereNull('deleted_at');
    90→
    91→			this.logger.debug(`Found ${results.length} alternatives for styleId ${styleId}`);
    92→			return results.map(
    93→				(result) =>
    94→					instanceToPlain<BaseStyleAlternativeDto>(result) as IStyleAlternativeBase,
    95→			);
    96→		} catch (error: unknown) {
    97→			const err = error instanceof Error ? error : new Error(String(error));
    98→			this.logger.error(
    99→				`Failed to find alternatives for styleId ${styleId}: ${err.message}`,
   100→			);
