   130→	async upsertStyleAlternative(
   131→		data: IStyleAlternativeCreate,
   132→	): Promise<IStyleAlternativeBase> {
   133→		try {
   134→			const upsertedAlternative: IStyleAlternativeBase = await this.knexWrite.transaction(
   135→				async (trx) => {
   136→					const existing = await trx<IStyleAlternativeBase>(this.tableName)
   137→						.where({
   138→							style_id: data.style_id,
   139→							alternative_style_id: data.alternative_style_id,
   140→						})
   141→						.whereNull('deleted_at')
   142→						.first();
   143→
   144→					if (existing) {
   145→						await trx(this.tableName)
   146→							.where({
   147→								style_id: data.style_id,
   148→								alternative_style_id: data.alternative_style_id,
   149→							})
   150→							.update({ updated_at: trx.fn.now() });
   151→					} else {
   152→						const _id = randomUUID();
   153→						const insertData: IStyleAlternativeCreate & {
   154→							_id: IStyleAlternativeBase['_id'];
   155→						} = {
   156→							_id,
   157→							style_id: data.style_id,
   158→							alternative_style_id: data.alternative_style_id,
   159→						};
   160→
   161→						const dto = plainToInstance(CreateStyleAlternativeDto, insertData);
   162→						const errors = await validate(dto);
   163→
   164→						if (errors.length > 0) {
   165→							this.logger.error(
   166→								`Validation failed for style alternative data: ${this.formatValidationErrors({ errors })}`,
   167→							);
   168→							throw new Error(
   169→								`Validation failed: ${this.formatValidationErrors({ errors })}`,
   170→							);
   171→						}
   172→
   173→						await trx(this.tableName).insert(insertData);
   174→					}
   175→
   176→					const result = await trx<IStyleAlternativeBase>(this.tableName)
   177→						.where({
   178→							style_id: data.style_id,
   179→							alternative_style_id: data.alternative_style_id,
   180→						})
   181→						.whereNull('deleted_at')
   182→						.first();
   183→
   184→					if (!result) {
   185→						throw new Error(
   186→							`Failed to upsert style alternative with style ID ${data.style_id} and alternative style ID ${data.alternative_style_id}`,
   187→						);
   188→					}
   189→
   190→					return result;
   191→				},
   192→			);
   193→
   194→			this.logger.debug(
   195→				`Upserted style alternative for styleId ${data.style_id} and alternativeStyleId ${data.alternative_style_id}`,
   196→			);
   197→
   198→			const styleDto = new BaseStyleAlternativeDto();
   199→			Object.assign(styleDto, upsertedAlternative);
   200→			return instanceToPlain<BaseStyleAlternativeDto>(styleDto) as IStyleAlternativeBase;
   201→		} catch (error: unknown) {
   202→			const err = error instanceof Error ? error : new Error(String(error));
   203→			this.logger.error(
   204→				`Failed to upsert style alternative with style ID ${data.style_id} and alternative style ID ${data.alternative_style_id}: ${err.message}`,
   205→			);
   206→			throw err;
   207→		}
   208→	}
