   210→	async bulkUpsertStyleAlternatives({
   211→		styleId,
   212→		alternativeStyleIds,
   213→	}: {
   214→		styleId: number;
   215→		alternativeStyleIds: number[];
   216→	}): Promise<void> {
   217→		if (alternativeStyleIds.length === 0) {
   218→			return;
   219→		}
   220→
   221→		try {
   222→			await this.knexWrite.transaction(async (trx) => {
   223→				const existingAlternatives = await trx<IStyleAlternativeBase>(this.tableName)
   224→					.select('alternative_style_id')
   225→					.where({ style_id: styleId })
   226→					.whereNull('deleted_at');
   227→
   228→				const existingIds = new Set(
   229→					existingAlternatives.map((a) => Number(a.alternative_style_id)),
   230→				);
   231→
   232→				const newAlternatives = alternativeStyleIds.filter((id) => !existingIds.has(id));
   233→
   234→				if (newAlternatives.length > 0) {
   235→					const insertData = newAlternatives.map((alternativeStyleId) => ({
   236→						_id: randomUUID(),
   237→						style_id: styleId,
   238→						alternative_style_id: alternativeStyleId,
   239→					}));
   240→
   241→					await trx(this.tableName).insert(insertData);
   242→				}
   243→
   244→				const idsToSoftDelete = [...existingIds].filter(
   245→					(id) => !alternativeStyleIds.includes(id),
   246→				);
   247→
   248→				if (idsToSoftDelete.length > 0) {
   249→					await trx(this.tableName)
   250→						.where({ style_id: styleId })
   251→						.whereIn('alternative_style_id', idsToSoftDelete)
   252→						.whereNull('deleted_at')
   253→						.update({
   254→							deleted_at: trx.fn.now(),
   255→							updated_at: trx.fn.now(),
   256→						});
   257→				}
   258→			});
   259→
   260→			this.logger.debug(
   261→				`Bulk upserted ${alternativeStyleIds.length} alternatives for styleId ${styleId}`,
   262→			);
   263→		} catch (error: unknown) {
   264→			const err = error instanceof Error ? error : new Error(String(error));
   265→			this.logger.error(
   266→				`Failed to bulk upsert style alternatives for styleId ${styleId}: ${err.message}`,
   267→			);
   268→			throw err;
   269→		}
   270→	}
   271→
   272→	async softDelete({
   273→		styleId,
   274→		alternativeStyleId,
   275→	}: {
   276→		styleId: IStyleAlternativeBase['style_id'];
   277→		alternativeStyleId: IStyleAlternativeBase['alternative_style_id'];
   278→	}): Promise<void> {
   279→		try {
   280→			await this.knexWrite(this.tableName)
   281→				.where({
   282→					style_id: styleId,
   283→					alternative_style_id: alternativeStyleId,
   284→				})
   285→				.whereNull('deleted_at')
   286→				.update({
   287→					deleted_at: this.knexWrite.fn.now(),
   288→					updated_at: this.knexWrite.fn.now(),
   289→				});
   290→
   291→			this.logger.debug(
   292→				`Soft deleted style alternative for styleId ${styleId} and alternativeStyleId ${alternativeStyleId}`,
   293→			);
   294→		} catch (error: unknown) {
   295→			const err = error instanceof Error ? error : new Error(String(error));
   296→			this.logger.error(
   297→				`Failed to soft delete style alternative for styleId ${styleId} and alternativeStyleId ${alternativeStyleId}: ${err.message}`,
   298→			);
   299→			throw err;
   300→		}
   301→	}
   302→
   303→	async softDeleteByStyleId({
   304→		styleId,
   305→	}: {
   306→		styleId: IStyleAlternativeBase['style_id'];
   307→	}): Promise<void> {
   308→		try {
   309→			await this.knexWrite(this.tableName)
   310→				.where({ style_id: styleId })
   311→				.whereNull('deleted_at')
   312→				.update({
   313→					deleted_at: this.knexWrite.fn.now(),
   314→					updated_at: this.knexWrite.fn.now(),
   315→				});
   316→
   317→			this.logger.debug(`Soft deleted all alternatives for styleId ${styleId}`);
   318→		} catch (error: unknown) {
   319→			const err = error instanceof Error ? error : new Error(String(error));
   320→			this.logger.error(
   321→				`Failed to soft delete alternatives for styleId ${styleId}: ${err.message}`,
   322→			);
   323→			throw err;
   324→		}
   325→	}
   326→
   327→	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
   328→		return errors
   329→			.map(
   330→				(error) =>
   331→					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
   332→			)
   333→			.join('; ');
   334→	}
   335→}
