   113→	async findByBrands({
   114→		brands,
   115→		limit,
   116→		categoryId,
   117→	}: {
   118→		brands: string[];
   119→		limit: number;
   120→		categoryId?: number;
   121→	}): Promise<IStylesMvBase[]> {
