	private parseStylesMvData(data: IStylesMvBase): IStylesMvBase {
		return {
			...data,
			sizes: this.parseJsonField(data.sizes),
			default_unit_prices: this.parseJsonField(data.default_unit_prices),
			colors: this.parseJsonField(data.colors),
			condensed_features: this.parseJsonField(data.condensed_features),
