	});

	it('should update existing alternative', async () => {
		const first = await model.upsertStyleAlternative({
			style_id: testStyleId,
			alternative_style_id: testAlternativeStyleId1,
		});

		await new Promise((resolve) => setTimeout(resolve, 100));

		const second = await model.upsertStyleAlternative({
			style_id: testStyleId,
			alternative_style_id: testAlternativeStyleId1,
		});

		expect(second._id).toBe(first._id);
		expect(second.updated_at.getTime()).toBeGreaterThanOrEqual(
			first.updated_at.getTime(),
		);
	});
});

