     9→import { BaseStylesMvDto } from '@modules/db/styles-mv/dto/styles-mv.base.dto';
    10→import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';
    11→
    12→import { styleStatus } from '@constants/common.constant';
    13→import {
    14→	KNEX_READ_CONNECTION,
    15→	KNEX_WRITE_CONNECTION,
    16→	TABLE_NAME_STYLES_MV,
    17→} from '@constants/db.constant';
    18→
    19→@Injectable()
    20→export class StylesMvModel {
    21→	private readonly logger = new Logger(StylesMvModel.name);
    22→	private readonly tableName = TABLE_NAME_STYLES_MV;
    23→
    24→	constructor(
    25→		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
    26→		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
    27→	) {}
    28→
    29→	async refreshForStyle({ styleId }: { styleId: number }): Promise<void> {
    30→		try {
    31→			await this.knexWrite.raw('CALL refresh_styles_mv(?)', [styleId]);
    32→			this.logger.debug(`Refreshed styles_mv for style ${styleId}`);
    33→		} catch (error: unknown) {
    34→			const err = error instanceof Error ? error : new Error(String(error));
    35→			this.logger.error(
    36→				`Failed to refresh styles_mv for style ${styleId}: ${err.message}`,
    37→			);
    38→			throw err;
    39→		}
    40→	}
    41→
    42→	async findByStyleId({
    43→		styleId,
    44→	}: {
    45→		styleId: IStylesMvBase['style_id'];
    46→	}): Promise<IStylesMvBase | null> {
    47→		try {
    48→			const result = await this.knexRead<BaseStylesMvDto>(this.tableName)
    49→				.where({ style_id: styleId })
    50→				.whereNull('deleted_at')
    51→				.first();
    52→
    53→			if (!result) {
    54→				this.logger.warn(`No styles_mv record found for styleId ${styleId}`);
    55→				return null;
    56→			}
    57→
    58→			this.logger.debug(`Found styles_mv record for styleId ${styleId}`);
    59→			return this.parseStylesMvData(result as unknown as IStylesMvBase);
    60→		} catch (error: unknown) {
    61→			const err = error instanceof Error ? error : new Error(String(error));
    62→			this.logger.error(
    63→				`Failed to find styles_mv for styleId ${styleId}: ${err.message}`,
    64→			);
    65→			throw err;
    66→		}
    67→	}
    68→
    69→	async findByStyleIds({
    70→		styleIds,
    71→		activeOnly = false,
    72→	}: {
    73→		styleIds: IStylesMvBase['style_id'][];
    74→		activeOnly?: boolean;
    75→	}): Promise<IStylesMvBase[]> {
    76→		if (styleIds.length === 0) {
    77→			return [];
    78→		}
    79→
    80→		const dto = plainToInstance(FindByStyleIdsDto, { styleIds, activeOnly });
    81→		const errors = await validate(dto);
    82→		if (errors.length > 0) {
    83→			this.logger.error(
    84→				`Validation failed for findByStyleIds: ${this.formatValidationErrors(errors)}`,
    85→			);
    86→			throw new Error(`Validation failed: ${this.formatValidationErrors(errors)}`);
    87→		}
    88→
    89→		try {
    90→			let query = this.knexRead<BaseStylesMvDto>(this.tableName)
    91→				.whereIn('style_id', styleIds)
    92→				.whereNull('deleted_at');
    93→
    94→			if (activeOnly) {
    95→				query = query.where('status', styleStatus.ACTIVE);
    96→			}
    97→
    98→			const results = await query;
    99→
   100→			this.logger.debug(
   101→				`Found ${results.length} styles_mv records for ${styleIds.length} styleIds${activeOnly ? ' (active only)' : ''}`,
   102→			);
   103→			return results.map((result) =>
   104→				this.parseStylesMvData(result as unknown as IStylesMvBase),
   105→			);
   106→		} catch (error: unknown) {
   107→			const err = error instanceof Error ? error : new Error(String(error));
   108→			this.logger.error(`Failed to find styles_mv by IDs: ${err.message}`);
   109→			throw err;
   110→		}
   111→	}
   112→
   113→	async findByBrands({
   114→		brands,
   115→		limit,
   116→		categoryId,
   117→	}: {
   118→		brands: string[];
   119→		limit: number;
   120→		categoryId?: number;
   121→	}): Promise<IStylesMvBase[]> {
   122→		if (brands.length === 0) {
   123→			return [];
   124→		}
   125→
   126→		const sanitizedBrands = this.sanitizeBrandNames(brands);
   127→		if (sanitizedBrands.length === 0) {
   128→			this.logger.warn('All brand names were filtered out during sanitization');
   129→			return [];
   130→		}
   131→
   132→		const dto = plainToInstance(FindByBrandsDto, { brands: sanitizedBrands, limit });
   133→		const errors = await validate(dto);
   134→		if (errors.length > 0) {
   135→			this.logger.error(
   136→				`Validation failed for findByBrands: ${this.formatValidationErrors(errors)}`,
   137→			);
