   141→		try {
   142→			let query = this.knexRead<BaseStylesMvDto>(this.tableName)
   143→				.whereNull('deleted_at')
   144→				.whereIn('brand', sanitizedBrands)
   145→				.where('status', styleStatus.ACTIVE);
   146→
   147→			if (categoryId !== undefined) {
   148→				query = query.where('primary_category_id', categoryId);
   149→			}
   150→
   151→			const results = await query.limit(limit);
   152→
   153→			this.logger.debug(
   154→				`Found ${results.length} styles_mv records for brands: ${brands.join(', ')}`,
   155→			);
   156→			return results.map((result) =>
   157→				this.parseStylesMvData(result as unknown as IStylesMvBase),
   158→			);
   159→		} catch (error: unknown) {
   160→			const err = error instanceof Error ? error : new Error(String(error));
   161→			this.logger.error(`Failed to find styles_mv by brands: ${err.message}`);
   162→			throw err;
   163→		}
   164→	}
   165→
   166→	async findAll({
   167→		limit,
   168→		offset,
   169→	}: {
   170→		limit: number;
   171→		offset: number;
   172→	}): Promise<IStylesMvBase[]> {
   173→		try {
   174→			const results = await this.knexRead<BaseStylesMvDto>(this.tableName)
   175→				.whereNull('deleted_at')
